const handleSubmit = async (e) => {
  e.preventDefault();
  setLoading(true);

  try {
    const result = await login(email, password);
    if (result.success) {
      // Store business ID in localStorage
      const businessId = result.data?.business?.id || result.data?.data?.business?.id;
      if (businessId) {
        localStorage.setItem('businessId', businessId);
        console.log('✅ Business ID stored:', businessId);
      }
      
      navigate('/dashboard');
      toast.success('Welcome back!');
    }
  } catch (error) {
    toast.error(error.message || 'Login failed');
  } finally {
    setLoading(false);
  }
};













